import kotlin.collections.Collections

fun solve(s: String): String {
    val result = mutableListOf<Char>()
    for (c in s) {
        when (c) {
            '*' -> {
                if (result.isNotEmpty()) {
                    result.removeLast()
                }
            }
            '#' -> {
                result.addAll(result)
            }
            '%' -> {
                Collections.reverse(result)
            }
